import { auth } from "./firebase";
import ky from "ky";

/**
 * A wrapper around `ky` (a tiny elegant HTTP client built on the native fetch API).
 * It automatically injects the Firebase JWT token into the Authorization header.
 */
export const apiClient = ky.create({
  prefixUrl: process.env.NEXT_PUBLIC_API_URL || "http://localhost:8080",
  hooks: {
    beforeRequest: [
      async (request) => {
        let token = null;
        if (auth.currentUser) {
          token = await auth.currentUser.getIdToken();
        } else if (typeof window !== "undefined") {
          token = window.sessionStorage.getItem("synqAuthToken");
        }

        if (token) {
          request.headers.set("Authorization", `Bearer ${token}`);
        }
      }
    ],
    afterResponse: [
      async (request, options, response) => {
        if (!response.ok) {
          let errorMsg = `API Error: ${response.status} ${response.statusText}`;
          try {
            const errorData = await response.clone().json();
            if (errorData.message) errorMsg = errorData.message;
          } catch (e) {
            // Ignore if not JSON
          }
          throw new Error(errorMsg);
        }
      }
    ]
  }
});

// For backward compatibility while we refactor to React Query
export async function fetchAPI(endpoint: string, options: RequestInit = {}) {
  // Translate the fetch options to ky options
  const kyOptions: Record<string, unknown> = {
    method: options.method || 'GET',
    headers: options.headers,
  };

  if (options.body) {
    if (typeof options.body === 'string') {
      try {
        kyOptions.json = JSON.parse(options.body);
      } catch (e) {
        kyOptions.body = options.body;
      }
    } else {
      kyOptions.body = options.body;
    }
  }

  // Remove leading slash if present since prefixUrl handles it
  const url = endpoint.startsWith('/') ? endpoint.slice(1) : endpoint;

  return apiClient(url, kyOptions).json();
}

